VALUES
  ('cpa-moex-00931', 'cpa', 'cpa-moex-106-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A上市公司（下稱A公司）之主要債務人今遭退票，退票金額高達新臺幣數億元，A公司遂於當晚7時， 將此消息輸入公開資訊觀測站，而A公司董事長甲於隔日上午開盤時立即賣出其手中所持有A公司之股 票及普通公司債。甲之行為是否違反禁止內線交易之規定？', '["賣出股票與普通公司債皆違法", "賣出股票與普通公司債皆未違法", "賣出股票違法，賣出普通公司債未違法", "賣出股票未違法，賣出普通公司債違法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "21d00306ef40", "answer_pdf_sha1": "dd265de3c045", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00932', 'cpa', 'cpa-moex-106-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '客戶甲委託A、B及C證券商買進某上市公司股票共計1億2千多萬元，但成交後甲未履行交付義務。 下列敘述，何者錯誤？', '["甲未依約交付，受委託之A、B及C證券商仍是應履行交付義務", "甲未依約交付，C證券商亦未履行交付義務，證券交易所可指定D證券商或其他證券商代為交付", "D證券商代為交付而發生價金差額及相關費用時，應由證券交易所直接動用其賠償準備金代為支付", "D證券商代為交付而發生價金差額及相關費用，若證券交易所因此有代為支付者，則證券交易所有權向 未履行交割之C證券商追償"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "21d00306ef40", "answer_pdf_sha1": "dd265de3c045", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00933', 'cpa', 'cpa-moex-106-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A公司持有已發行有表決權股份總數1000萬股之B上櫃公司（下稱B公司）股票350萬股，今A公司 擬再增加持有B公司之股票。以下敘述，何者錯誤？', '["若A公司擬以公開收購方式取得B公司股票，其應先向主管機關申報並公告後，始得為之", "若A公司非以現金為對價公開收購B公司股票，其無須提出具有履行支付收購對價能力之證明", "若A公司預計於同年8月1日至9月10日期間，取得B公司股票250萬股，則A公司只能以公開收 購方式取得", "一旦A公司進行B公司股票之公開收購，則其不得降低預定之公開收購數量及縮短公開收購期間"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "21d00306ef40", "answer_pdf_sha1": "dd265de3c045", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00934', 'cpa', 'cpa-moex-106-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A上市公司（下稱A公司）依證券交易法令之規定，下列何者無需主動事先向投資人交付公開說明書或 對市場公開相關資訊？', '["辦理現金增資募集發行新股", "辦理可轉換公司債之募集發行", "向符合認購資格之法人私募發行特別股", "A公司擬與B公司共同對C上市公司之不特定股東以現金為對價公開收購C上市公司已發行之50%普 通股股份"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "21d00306ef40", "answer_pdf_sha1": "dd265de3c045", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00935', 'cpa', 'cpa-moex-106-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '關於證券交易法中財務報告編製之相關規定，下列敘述，何者錯誤？', '["主管機關依證券交易法授權所定之證券發行人財務報告編製準則不應抵觸商業會計法之規定", "公開發行公司之年度財務報告及每季財務報告均應提報董事會", "公開發行公司除情形特殊，經主管機關另予規定者外，應在每月10日以前公告並申報上月份營運情形", "財務報告應經董事長、經理人及會計主管簽名或蓋章"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "21d00306ef40", "answer_pdf_sha1": "dd265de3c045", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00936', 'cpa', 'cpa-moex-106-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '關於公開說明書內容有虛偽或隱匿之情事，下列敘述，何者正確？', '["董事長若不知道且未參與公開說明書之編製，即無需對該公開說明書負刑事及民事責任", "發行人所編製之公開說明書若係委託承銷商製作，則民事賠償責任僅限於承銷商，發行人無庸負責", "會計師若因過失而將不實之重要資訊使用於簽證報告中或未能使財務報告正確表達者，僅有民事責 任，尚無刑事責任", "公司財務長明知為不實之重要資訊記載於公開說明書而簽名證實其內容真正者，僅負刑事責任而無民 事責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "21d00306ef40", "answer_pdf_sha1": "dd265de3c045", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00937', 'cpa', 'cpa-moex-106-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A證券商與B證券商因買賣有價證券，主張B證券商應賠償其損失。A證券商應循下列何種途徑解決爭 議？', '["訴訟", "仲裁", "調解", "調處"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "21d00306ef40", "answer_pdf_sha1": "dd265de3c045", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00938', 'cpa', 'cpa-moex-106-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A 證券商近來因股市低迷，目前自行停止營業。依證券交易法之規定，證券商如已開業而自行停止營業 連續達多久以上時，主管機關得撤銷其許可？', '["一個月", "一個半月", "二個月", "三個月"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "21d00306ef40", "answer_pdf_sha1": "dd265de3c045", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00939', 'cpa', 'cpa-moex-106-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '依商業會計處理準則規定，記帳憑證保管期限屆滿，應經何人核准，方得予以銷毀？', '["代表商業之負責人", "經理人", "主辦會計人員", "經辦會計人員"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "21d00306ef40", "answer_pdf_sha1": "dd265de3c045", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00940', 'cpa', 'cpa-moex-106-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '商業之利害關係人，得因正當理由，向下列何者聲請選派檢查員，以檢查該商業之帳簿報表及憑證？', '["商業會計法之主管機關", "法院", "該商業之目的事業主管機關", "審計部"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "21d00306ef40", "answer_pdf_sha1": "dd265de3c045", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
